const rows = $input.all().map(i => i.json);
const today = new Date();
const pad = n => String(n).padStart(2,'0');
const isoToday = `${today.getFullYear()}-${pad(today.getMonth()+1)}-${pad(today.getDate())}`;

// Filtrar pagos que vencen hoy o en los próximos 3 días
const upcoming = [];

for (const r of rows) {
  const meta = r.metadata || {};
  const dueDay = meta.due_day || meta.billing_day;
  if (!dueDay) continue;

  // Calcular próxima fecha de vencimiento este mes
  const dueDate = new Date(today.getFullYear(), today.getMonth(), parseInt(dueDay));
  if (dueDate < today) dueDate.setMonth(dueDate.getMonth()+1); // siguiente mes
  const diffMs = dueDate.getTime() - today.getTime();
  const diffDays = Math.floor(diffMs / 86400000);

  if (diffDays >= 0 && diffDays <= 3) {
    upcoming.push({
      label: meta.label || r.content || 'Pago',
      amount: meta.amount || 0,
      account: meta.account_hint || meta.bank || '',
      dueDay,
      diffDays,
      type: r.type,
    });
  }
}

if (upcoming.length === 0) {
  return [{ json: { skip: true, mensaje: 'Sin pagos próximos' } }];
}

const lines = upcoming.map(p => {
  const icon = p.type === 'income' ? '💰' : '💸';
  const days = p.diffDays === 0 ? '*¡HOY!*' : `en ${p.diffDays} día${p.diffDays>1?'s':''}`;
  const acct = p.account ? ` (@${p.account})` : '';
  return `${icon} ${p.label}${acct}: $${parseFloat(p.amount).toFixed(2)} — ${days} (día ${p.dueDay})`;
}).join('\n');

const mensaje = [
  `📅 *Nexus OS — Agenda Financiera*`,
  ``,
  `Pagos próximos:`,
  lines,
  ``,
  `🔗 Ver agenda: nexus-os-chi.vercel.app/app`,
].join('\n');

return [{ json: { skip: false, mensaje, count: upcoming.length } }];
